 47→const formatTitle = (item: NotificationItem): string => {
 48→  if (item.message) return item.message;
 49→  const name = item.users?.name || 'Someone';
 50→  switch (item.type) {
 51→    case 'like': return `${name} liked your post`;
 52→    case 'comment': return `${name} commented on your post`;
 53→    case 'repost': return `${name} reposted your post`;
 54→    case 'reply': return `${name} replied`;
 55→    case 'match': return `${name} matched with you`;
 56→    default: return 'Notification';
 57→  }
 58→};
