 352→const isPrivateIpv4Address = (ip) => {
 353→    const parts = ip.split('.').map((part) => Number(part));
 354→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
 355→        return true;
 356→    }
 357→
 358→    const [a, b] = parts;
 359→    if (a === 10 || a === 127 || a === 0) return true;
 360→    if (a === 169 && b === 254) return true;
 361→    if (a === 172 && b >= 16 && b <= 31) return true;
 362→    if (a === 192 && b === 168) return true;
 363→    return false;
 364→};
