 649→// ── Profile share route: composite OG image for social media ──
 650→app.get('/share/u/:username/image', async (req, res) => {
 651→    const { username } = req.params;
 652→    await ensureShareFonts();
 653→
 654→    try {
 655→        const result = await getUserByUsernameService(username);
 656→        const user = result?.userData?.[0];
 657→        if (!user) {
 658→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 659→        }
 660→
 661→        const displayName = normalizeWhitespace(user.name) || username;
 662→        const handle = `@${normalizeWhitespace(user.username || username)}`;
 663→        const bio = toPreviewText(user.bio || '', 120);
 664→
 665→        // ── Fetch background image ──
 666→        let bgBuffer = null;
 667→        const bgStyle = user.background || {};
 668→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
 669→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
 670→            : null;
 671→        const bgImageUrl = bgImageMatch?.[1];
 672→
 673→        if (bgImageUrl) {
 674→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
 675→            if (bgEval.ok && bgEval.resolvedUrl) {
 676→                try {
 677→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
 678→                    bgBuffer = remote.buffer;
 679→                } catch { /* use fallback gradient */ }
 680→            }
 681→        }
 682→
 683→        // ── Base layer: background or dark gradient ──
 684→        let baseLayer;
 685→        if (bgBuffer) {
 686→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
 687→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
 688→                .toBuffer();
 689→        } else {
 690→            // Use profile's solid background color if available, otherwise dark fallback
 691→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
 692→                ? bgStyle.background.trim()
 693→                : null;
 694→            const gradientSvg = solidColor
 695→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 696→                    <rect width="100%" height="100%" fill="${solidColor}"/>
 697→                </svg>`
 698→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 699→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
 700→                        <stop offset="0%" stop-color="#1a1a2e"/>
 701→                        <stop offset="100%" stop-color="#16213e"/>
 702→                    </linearGradient></defs>
 703→                    <rect width="100%" height="100%" fill="url(#g)"/>
 704→                </svg>`;
 705→            baseLayer = await sharp(Buffer.from(gradientSvg))
 706→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
 707→                .png()
 708→                .toBuffer();
 709→        }
 710→
 711→        // ── Dark overlay for text readability ──
 712→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 713→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 714→        </svg>`;
 715→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 716→
 717→        // ── Circular avatar ──
 718→        let avatarComposite = null;
 719→        const avatarSize = 180;
 720→        const avatarUrl = user.image_url;
 721→        if (avatarUrl) {
 722→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 723→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 724→                try {
 725→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 726→                    const circleMask = Buffer.from(
 727→                        `<svg width="${avatarSize}" height="${avatarSize}">
 728→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 729→                        </svg>`
 730→                    );
 731→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 732→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 733→                        .png()
 734→                        .toBuffer();
 735→                    const circularAvatar = await sharp(resizedAvatar)
 736→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 737→                        .png()
 738→                        .toBuffer();
 739→                    avatarComposite = circularAvatar;
 740→                } catch { /* skip avatar */ }
 741→            }
 742→        }
 743→
 744→        // ── Compose all layers ──
 745→        const composites = [
 746→            { input: overlayBuffer, top: 0, left: 0 },
 747→        ];
 748→
 749→        if (avatarComposite) {
 750→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 751→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 752→        }
 753→
 754→        const finalImage = await sharp(baseLayer)
 755→            .composite(composites)
 756→            .jpeg({ quality: 82, mozjpeg: true })
 757→            .toBuffer();
 758→
 759→        res.set('Content-Type', 'image/jpeg');
 760→        res.set('Cache-Control', 'public, max-age=3600');
 761→        return res.send(finalImage);
 762→    } catch (err) {
 763→        console.error('profile share image route error:', err?.message || err);
 764→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 765→    }
 766→});
