 33→const extractBearerToken = (authHeader = "") => {
 34→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
 35→    if (!trimmed) return "";
 36→
 37→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
 38→    if (bearerMatch?.[1]) {
 39→        return bearerMatch[1].trim();
 40→    }
 41→
 42→    return trimmed;
 43→};
