import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import type { AuthChangeEvent, Session, User } from '@supabase/auth-js';
import { IS_SUPABASE_CONFIGURED } from '../../config/env';
import * as supabaseModule from '../../lib/supabase';

type Credentials = {
  email: string;
  password: string;
};

type AuthContextValue = {
  user: User | null;
  session: Session | null;
  loading: boolean;
  authError: string | null;
  signIn: (credentials: Credentials) => Promise<void>;
  signUp: (credentials: Credentials) => Promise<void>;
  signOut: () => Promise<void>;
};

const AuthContext = createContext<AuthContextValue | undefined>(undefined);

const notConfiguredMessage =
  'Supabase is not configured. Set ISK_MOBILE_SUPABASE_URL and ISK_MOBILE_SUPABASE_ANON_KEY before using auth flows.';
const unavailableClientMessage =
  'Supabase client is unavailable. Restart Metro with --reset-cache and relaunch the app.';

const supabase = supabaseModule?.supabase;

const resolveAuthClient = () => {
  if (!IS_SUPABASE_CONFIGURED) {
    throw new Error(notConfiguredMessage);
  }
  if (!supabase) {
    throw new Error(unavailableClientMessage);
  }

  return supabase.auth;
};

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);
  const [authError, setAuthError] = useState<string | null>(null);

  useEffect(() => {
    let mounted = true;

    if (!IS_SUPABASE_CONFIGURED) {
      setAuthError(notConfiguredMessage);
      setLoading(false);
      return () => {
        mounted = false;
      };
    }

    if (!supabase) {
      setAuthError(unavailableClientMessage);
      setLoading(false);
      return () => {
        mounted = false;
      };
    }

    setAuthError(null);

    (async () => {
      try {
        const { data, error } = await supabase.auth.getSession();
        if (!mounted) {
          return;
        }

        if (error) {
          setAuthError(error.message);
        } else {
          setAuthError(null);
        }

        setSession(data.session ?? null);
      } catch (error) {
        if (!mounted) {
          return;
        }

        setAuthError(error instanceof Error ? error.message : 'Failed to load auth session.');
      } finally {
        if (mounted) {
          setLoading(false);
        }
      }
    })();

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event: AuthChangeEvent, nextSession: Session | null) => {
      setSession(nextSession);
      setAuthError(null);
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, []);

  const value = useMemo<AuthContextValue>(
    () => ({
      user: session?.user ?? null,
      session,
      loading,
      authError,
      signIn: async ({ email, password }) => {
        const auth = resolveAuthClient();
        setAuthError(null);

        try {
          const { error } = await auth.signInWithPassword({ email, password });
          if (error) {
            throw error;
          }
        } catch (error) {
          const message = error instanceof Error ? error.message : 'Sign in failed.';
          setAuthError(message);
          throw error;
        }
      },
      signUp: async ({ email, password }) => {
        const auth = resolveAuthClient();
        setAuthError(null);

        try {
          const { error } = await auth.signUp({ email, password });
          if (error) {
            throw error;
          }
        } catch (error) {
          const message = error instanceof Error ? error.message : 'Sign up failed.';
          setAuthError(message);
          throw error;
        }
      },
      signOut: async () => {
        const auth = resolveAuthClient();
        setAuthError(null);

        try {
          const { error } = await auth.signOut();
          if (error) {
            throw error;
          }
        } catch (error) {
          const message = error instanceof Error ? error.message : 'Sign out failed.';
          setAuthError(message);
          throw error;
        }
      },
    }),
    [authError, loading, session],
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }

  return context;
}

